import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { localCart, localEvents, localOrders, analyticsAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';

const CheckoutPage = ({ onToast }) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const cart = localCart.get();
  const [form, setForm] = useState({ name: user?.name || '', email: user?.email || '', address: '', city: '', pin: '', card: '' });
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [placedOrder, setPlacedOrder] = useState(null);

  const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);
  const set = k => e => setForm(f => ({ ...f, [k]: e.target.value }));

  const handleOrder = async (e) => {
    e.preventDefault();
    setLoading(true);
    const orderId   = 'TG' + Date.now().toString().slice(-8);
    const sessionId = sessionStorage.getItem('u_session') || 'no-session';

    for (const item of cart) {
      const ev = { sessionId, userId: user?.id, productId: item.id, productName: item.name,
        category: item.category, price: item.price, quantity: item.quantity,
        emoji: item.emoji, brand: item.brand, actionType: 'purchase' };
      localEvents.add({ ...ev, timestamp: new Date().toISOString() });
      try { await analyticsAPI.track(ev); } catch {}
    }

    // Save order to localStorage
    const order = {
      orderId,
      items: cart.map(i => ({ ...i })),
      total,
      delivery: { name: form.name, email: form.email, address: form.address, city: form.city, pin: form.pin },
      status: 'active',
      placedAt: new Date().toISOString(),
    };
    localOrders.add(order);
    setPlacedOrder(order);

    localCart.clear();
    window.dispatchEvent(new Event('cartUpdated'));
    window.dispatchEvent(new Event('eventsUpdated'));
    window.dispatchEvent(new Event('ordersUpdated'));
    setLoading(false);
    setSuccess(true);
    onToast?.('🎉 Order placed successfully!', 'success');
  };

  if (cart.length === 0 && !success) return (
    <div className="text-center py-5">
      <div style={{ fontSize: '4rem' }}>🛒</div>
      <h5 className="fw-bold mt-3">Cart is empty</h5>
      <button className="btn btn-warning mt-2" onClick={() => navigate('/products')}>Browse Products</button>
    </div>
  );

  if (success && placedOrder) return (
    <div className="text-center py-5">
      <div style={{ fontSize: '5rem' }}>🎉</div>
      <h3 className="fw-bold text-success mt-3">Order Placed!</h3>
      <p className="text-muted">Order ID: <strong className="text-dark">{placedOrder.orderId}</strong></p>
      <p className="text-muted">Total paid: <strong className="text-success">₹{total.toLocaleString('en-IN')}</strong></p>
      <div className="alert alert-success d-inline-block mt-2 small">
        ✅ Order saved — view & cancel anytime in <strong>My Orders</strong>
      </div>
      <div className="mt-4 d-flex gap-2 justify-content-center flex-wrap">
        <button className="btn btn-warning fw-bold" onClick={() => navigate('/products')}>🛍️ Shop More</button>
        <button className="btn btn-dark fw-bold" onClick={() => navigate('/orders')}>📦 My Orders</button>
        <button className="btn btn-outline-dark" onClick={() => navigate('/dashboard')}>📊 Dashboard</button>
      </div>
    </div>
  );

  return (
    <div>
      <h4 className="fw-bold mb-4">💳 Checkout</h4>
      <div className="row g-4">
        <div className="col-lg-7">
          <form onSubmit={handleOrder}>
            <div className="card border-0 shadow-sm mb-3">
              <div className="card-header bg-dark text-white fw-bold">📦 Delivery Details</div>
              <div className="card-body">
                <div className="row g-3">
                  <div className="col-md-6">
                    <label className="form-label small fw-semibold">Full Name</label>
                    <input className="form-control" value={form.name} onChange={set('name')} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label small fw-semibold">Email</label>
                    <input type="email" className="form-control" value={form.email} onChange={set('email')} required />
                  </div>
                  <div className="col-12">
                    <label className="form-label small fw-semibold">Address</label>
                    <input className="form-control" placeholder="Street address" value={form.address} onChange={set('address')} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label small fw-semibold">City</label>
                    <input className="form-control" value={form.city} onChange={set('city')} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label small fw-semibold">PIN Code</label>
                    <input className="form-control" maxLength={6} value={form.pin} onChange={set('pin')} required />
                  </div>
                </div>
              </div>
            </div>
            <div className="card border-0 shadow-sm mb-3">
              <div className="card-header bg-dark text-white fw-bold">💳 Payment</div>
              <div className="card-body">
                <div className="mb-3">
                  <label className="form-label small fw-semibold">Card Number</label>
                  <input className="form-control" placeholder="1234 5678 9012 3456" maxLength={19}
                    value={form.card} onChange={e => setForm(f => ({ ...f, card: e.target.value.replace(/\D/g,'').replace(/(.{4})/g,'$1 ').trim() }))} required />
                </div>
                <div className="row g-2">
                  <div className="col-6">
                    <label className="form-label small fw-semibold">Expiry</label>
                    <input className="form-control" placeholder="MM/YY" required />
                  </div>
                  <div className="col-6">
                    <label className="form-label small fw-semibold">CVV</label>
                    <input type="password" className="form-control" placeholder="•••" maxLength={3} required />
                  </div>
                </div>
              </div>
            </div>
            <button type="submit" className="btn btn-warning btn-lg fw-bold w-100" disabled={loading}>
              {loading ? <><span className="spinner-border spinner-border-sm me-2"/>Processing...</> : `🎉 Place Order — ₹${total.toLocaleString('en-IN')}`}
            </button>
          </form>
        </div>
        <div className="col-lg-5">
          <div className="card border-0 shadow-sm">
            <div className="card-header bg-dark text-white fw-bold">🧾 Order Summary</div>
            <div className="card-body">
              {cart.map(i => (
                <div key={i.id} className="d-flex gap-2 mb-3 align-items-start">
                  <span style={{ fontSize: '1.5rem' }}>{i.emoji}</span>
                  <div className="flex-grow-1">
                    <div className="small fw-semibold">{i.name}</div>
                    <div className="text-muted" style={{ fontSize: '0.7rem' }}>Qty: {i.quantity}</div>
                  </div>
                  <div className="fw-bold text-success small">₹{(i.price * i.quantity).toLocaleString('en-IN')}</div>
                </div>
              ))}
              <hr />
              <div className="d-flex justify-content-between fw-bold">
                <span>Total</span>
                <span className="text-success fs-5">₹{total.toLocaleString('en-IN')}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CheckoutPage;
